#ifndef GEMM_N128_K2048_KERNEL_H
#define GEMM_N128_K2048_KERNEL_H

#include <cuda_runtime.h>

#if defined(__CUDACC__)
#include <cuda_fp16.h>
#endif

// C[M,128] = A[M,2048] * B[128,2048]^T
// A: row-major [M,K], B: row-major [N,K], C: row-major [M,N]
void gemm_n128_k2048_launch(const half* A, const half* B, half* C, int M, cudaStream_t stream);

#endif // GEMM_N128_K2048_KERNEL_H

#include "kernel.h"

#include <cuda.h>
#include <cuda_fp16.h>
#include <mma.h>

using namespace nvcuda;

static constexpr int WMMA_M = 16;
static constexpr int WMMA_N = 16;
static constexpr int WMMA_K = 16;

static constexpr int N_CONST = 128;
static constexpr int K_CONST = 2048;

// Use a 64x128 CTA tile so grid.y == 1 (since N is exactly 128).
static constexpr int WARPS_M = 4;   // 64 rows
static constexpr int WARPS_N = 8;   // 128 cols
static constexpr int WARPS_PER_BLOCK = WARPS_M * WARPS_N; // 32 warps
static constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * 32; // 1024 threads (max)

static constexpr int TILE_M = WARPS_M * WMMA_M; // 64
static constexpr int TILE_N = WARPS_N * WMMA_N; // 128

// Shared memory per k-slice:
// A_sh: [64,16] half
// B_sh: [16,128] half (K-major)
// C_sh: [64,128] float
__global__ void gemm_n128_k2048_wmma_64x128(const half* __restrict__ A,
                                           const half* __restrict__ B,
                                           half* __restrict__ C,
                                           int M) {
  extern __shared__ __align__(16) unsigned char smem_raw[];
  half* A_sh = reinterpret_cast<half*>(smem_raw);
  half* B_sh = A_sh + (TILE_M * WMMA_K);
  float* C_sh = reinterpret_cast<float*>(B_sh + (WMMA_K * TILE_N));

  const int tid = threadIdx.x;
  const int warp_id = tid >> 5;  // 0..31
  const int lane = tid & 31;

  const int block_m0 = int(blockIdx.x) * TILE_M;
  // blockIdx.y is unnecessary since TILE_N == N_CONST, but keep for safety
  const int block_n0 = int(blockIdx.y) * TILE_N;

  const int warp_m = warp_id / WARPS_N; // 0..3
  const int warp_n = warp_id % WARPS_N; // 0..7

  wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> c_frag;
  wmma::fill_fragment(c_frag, 0.0f);

  // K loop (2048/16 = 128 iterations)
  #pragma unroll 1
  for (int k0 = 0; k0 < K_CONST; k0 += WMMA_K) {
    // Load A_sh: [64,16] row-major
    for (int idx = tid; idx < TILE_M * WMMA_K; idx += blockDim.x) {
      const int r = idx >> 4; // /16
      const int c = idx & 15;
      const int gr = block_m0 + r;
      half v = __float2half(0.0f);
      if (gr < M) v = A[gr * K_CONST + (k0 + c)];
      A_sh[r * WMMA_K + c] = v;
    }

    // Load B_sh: [16,128] (k_local-major)
    for (int idx = tid; idx < WMMA_K * TILE_N; idx += blockDim.x) {
      const int k_local = idx / TILE_N;          // 0..15
      const int n_local = idx - k_local*TILE_N;  // 0..127
      const int gn = block_n0 + n_local;         // 0..127 (in-bounds)
      // gn is always < 128 for grid.y=1, but keep bounds for robustness.
      half v = __float2half(0.0f);
      if (gn < N_CONST) v = B[gn * K_CONST + (k0 + k_local)];
      B_sh[k_local * TILE_N + n_local] = v;
    }

    __syncthreads();

    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, half, wmma::row_major> a_frag;
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, half, wmma::col_major> b_frag;

    const half* a_ptr = &A_sh[(warp_m * WMMA_M) * WMMA_K];
    const half* b_ptr = &B_sh[(0 * TILE_N) + (warp_n * WMMA_N)];

    wmma::load_matrix_sync(a_frag, a_ptr, WMMA_K);
    wmma::load_matrix_sync(b_frag, b_ptr, TILE_N);

    wmma::mma_sync(c_frag, a_frag, b_frag, c_frag);

    __syncthreads();
  }

  // Store warp tile to shared then to global.
  float* warp_out = C_sh + (warp_m * WMMA_M) * TILE_N + (warp_n * WMMA_N);
  wmma::store_matrix_sync(warp_out, c_frag, TILE_N, wmma::mem_row_major);

  __syncthreads();

  // Write out global C
  for (int idx = tid; idx < TILE_M * TILE_N; idx += blockDim.x) {
    const int r = idx / TILE_N;
    const int c = idx - r * TILE_N;
    const int gr = block_m0 + r;
    const int gc = block_n0 + c;
    if (gr < M && gc < N_CONST) {
      C[gr * N_CONST + gc] = __float2half_rn(C_sh[idx]);
    }
  }

  (void)lane;
}

void gemm_n128_k2048_launch(const half* A, const half* B, half* C, int M, cudaStream_t stream) {
  dim3 block(THREADS_PER_BLOCK, 1, 1);
  dim3 grid((M + TILE_M - 1) / TILE_M, (N_CONST + TILE_N - 1) / TILE_N, 1); // grid.y == 1

  const size_t shmem_bytes =
      size_t(TILE_M * WMMA_K) * sizeof(half) +     // A_sh
      size_t(WMMA_K * TILE_N) * sizeof(half) +     // B_sh
      size_t(TILE_M * TILE_N) * sizeof(float);     // C_sh

  // Prefer shared memory carveout to SMEM if possible (helps on Ampere in some cases)
  cudaFuncSetAttribute(gemm_n128_k2048_wmma_64x128,
                       cudaFuncAttributePreferredSharedMemoryCarveout,
                       cudaSharedmemCarveoutMaxShared);

  gemm_n128_k2048_wmma_64x128<<<grid, block, shmem_bytes, stream>>>(A, B, C, M);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <cuda_runtime.h>
#include <limits>
#include <string>

#include "kernel.h"

static void check_input(const torch::Tensor& t, const char* name) {
  TORCH_CHECK(t.defined(), name, " must be defined");
  TORCH_CHECK(t.device().is_cuda(), name, " must be a CUDA tensor");
  TORCH_CHECK(t.is_contiguous(), name, " must be contiguous");
  TORCH_CHECK(t.dtype() == torch::kFloat16, name, " must be float16");
}

static void check_shapes(const torch::Tensor& A, const torch::Tensor& B) {
  TORCH_CHECK(A.dim() == 2, "A must be rank-2 [M,K], got dim=", A.dim());
  TORCH_CHECK(B.dim() == 2, "B must be rank-2 [N,K], got dim=", B.dim());
  TORCH_CHECK(A.size(1) == 2048, "A.size(1) (K) must be 2048, got ", A.size(1));
  TORCH_CHECK(B.size(0) == 128,  "B.size(0) (N) must be 128, got ", B.size(0));
  TORCH_CHECK(B.size(1) == 2048, "B.size(1) (K) must be 2048, got ", B.size(1));
}

torch::Tensor run(torch::Tensor A,
                  torch::Tensor B,
                  torch::optional<torch::Dict<std::string, torch::Tensor>> kwargs = {}) {
  // kwargs accepted for API compatibility (unused)
  (void)kwargs;

  check_input(A, "A");
  check_input(B, "B");
  check_shapes(A, B);
  TORCH_CHECK(A.device() == B.device(), "A and B must be on the same CUDA device");

  const int64_t M64 = A.size(0);
  TORCH_CHECK(M64 >= 0, "A.size(0) (M) must be non-negative, got ", M64);
  TORCH_CHECK(M64 <= std::numeric_limits<int>::max(), "M too large for int: ", M64);
  const int M = static_cast<int>(M64);

  auto C = torch::empty({A.size(0), 128},
                        torch::TensorOptions().device(A.device()).dtype(torch::kFloat16));

  const half* A_ptr = reinterpret_cast<const half*>(A.data_ptr<at::Half>());
  const half* B_ptr = reinterpret_cast<const half*>(B.data_ptr<at::Half>());
  half* C_ptr = reinterpret_cast<half*>(C.data_ptr<at::Half>());

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();

  // Clear any pre-existing error, then launch
  (void)cudaGetLastError();
  gemm_n128_k2048_launch(A_ptr, B_ptr, C_ptr, M, stream);

  cudaError_t launch_err = cudaGetLastError();
  TORCH_CHECK(launch_err == cudaSuccess,
              "CUDA kernel launch failed: ", cudaGetErrorString(launch_err));

  // NOTE: synchronize for correctness in this benchmark harness.
  cudaError_t sync_err = cudaStreamSynchronize(stream);
  TORCH_CHECK(sync_err == cudaSuccess,
              "CUDA kernel execution failed: ", cudaGetErrorString(sync_err));

  return C;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "gemm_n128_k2048 (CUDA): C = A @ B.T",
        pybind11::arg("A"), pybind11::arg("B"), pybind11::arg("kwargs") = pybind11::none());
}
